parameters.command:
node - <<'NODE'
const { execFileSync } = require('node:child_process');

const apiBase = process.env.PAPERCLIP_API_URL || 'http://127.0.0.1:3100';
const companyId = process.env.PAPERCLIP_COMPANY_ID || '6a41f388-ff8d-4b65-82dc-38a9b66fa69e';
const apiKey = process.env.PAPERCLIP_API_KEY || '';
const cliCommand = (process.env.PAPERCLIP_CLI_COMMAND || 'npx -y paperclipai').trim();
const cliArgv = cliCommand.split(/\s+/).filter(Boolean);
function stripTrailingSlash(value) {
  return String(value || '').replace(/\/+$/, '');
}

function resolveAppBase(rawBase) {
  const override = stripTrailingSlash((process.env.PAPERCLIP_PUBLIC_URL || '').trim());
  if (override) return override;
  try {
    const parsed = new URL(rawBase);
    const host = parsed.hostname.toLowerCase();
    if (host === '127.0.0.1' || host === 'localhost' || host === '0.0.0.0') {
      const port = parsed.port ? `:${parsed.port}` : '';
      return `${parsed.protocol}//raspberrypi${port}`;
    }
    return stripTrailingSlash(rawBase);
  } catch {
    return stripTrailingSlash(rawBase);
  }
}

const source = {
  mode: 'paperclip_cli_n8n',
  cli_command: cliCommand,
  api_base: stripTrailingSlash(apiBase),
  app_base: resolveAppBase(apiBase),
  company_id: companyId,
};

function emit(payload) {
  process.stdout.write(JSON.stringify(payload));
}

function cliJson(args) {
  const stdout = execFileSync(
    cliArgv[0],
    [...cliArgv.slice(1), ...args, '--company-id', companyId, '--api-base', apiBase, '--api-key', apiKey, '--json'],
    {
      encoding: 'utf8',
      stdio: ['ignore', 'pipe', 'pipe'],
    },
  );
  return JSON.parse(stdout);
}

function compactIssues(rows) {
  return (Array.isArray(rows) ? rows : []).map((row) => ({
    id: row.id || null,
    identifier: row.identifier || null,
    title: row.title || null,
    status: row.status || null,
    parentId: row.parentId || null,
    assigneeAgentId: row.assigneeAgentId || null,
    assigneeUserId: row.assigneeUserId || null,
    updatedAt: row.updatedAt || null,
  }));
}

function compactApprovals(rows) {
  return (Array.isArray(rows) ? rows : []).map((row) => ({
    id: row.id || null,
    type: row.type || null,
    status: row.status || null,
    issueIds: Array.isArray(row.issueIds) ? row.issueIds : [],
    payload: row.payload && typeof row.payload === 'object'
      ? { title: row.payload.title || null, name: row.payload.name || null, agentId: row.payload.agentId || null }
      : {},
    requestedByAgentId: row.requestedByAgentId || null,
    requestedByUserId: row.requestedByUserId || null,
    updatedAt: row.updatedAt || null,
  }));
}

function compactAgents(rows) {
  return (Array.isArray(rows) ? rows : []).map((row) => ({
    id: row.id || null,
    name: row.name || null,
    runtimeConfig: row.runtimeConfig || {},
    lastHeartbeatAt: row.lastHeartbeatAt || null,
  }));
}

function compactHeartbeatRuns(rows) {
  return (Array.isArray(rows) ? rows : []).map((row) => ({
    agentId: row.agentId || null,
    invocationSource: row.invocationSource || null,
    startedAt: row.startedAt || null,
  }));
}

(async () => {
  if (!apiKey) {
    emit({
      success: false,
      error_code: 'paperclip_api_key_missing',
      message: 'PAPERCLIP_API_KEY is not configured in the n8n container',
      remediation: [
        'Set PAPERCLIP_API_KEY in docker-compose.n8n.yml or container env',
        'Restart n8n after updating the environment',
      ],
      source,
    });
    process.exit(0);
  }

  try {
    const issues = compactIssues(cliJson(['issue', 'list']));
    const inferredCompanyPrefix =
      (process.env.PAPERCLIP_COMPANY_PREFIX || '').trim() ||
      issues
        .map((issue) => {
          const match = /^([A-Za-z][A-Za-z0-9_]*)-\d+$/.exec(issue.identifier || '');
          return match ? match[1].toUpperCase() : null;
        })
        .find(Boolean) ||
      'ROB';
    source.company_prefix = inferredCompanyPrefix;
    const approvals = compactApprovals(cliJson(['approval', 'list']));
    const agents = compactAgents(cliJson(['agent', 'list']));

    const payload = {
      success: true,
      generated_at: new Date().toISOString(),
      source,
      warnings: [],
      snapshot: {
        issues,
        approvals,
        agents,
        heartbeat_runs: [],
      },
    };

    try {
      const response = await fetch(`${apiBase}/api/companies/${companyId}/heartbeat-runs?limit=200`, {
        headers: {
          accept: 'application/json',
          authorization: `Bearer ${apiKey}`,
        },
      });
      if (response.ok) {
        payload.snapshot.heartbeat_runs = compactHeartbeatRuns(await response.json());
      } else {
        payload.warnings.push(`heartbeat-runs HTTP fallback unavailable: ${response.status}`);
      }
    } catch (error) {
      payload.warnings.push(`heartbeat-runs HTTP fallback error: ${error.message || String(error)}`);
    }

    emit(payload);
    process.exit(0);
  } catch (error) {
    emit({
      success: false,
      error_code: 'snapshot_collection_failed',
      message: error.message || String(error),
      source,
    });
    process.exit(0);
  }
})();
NODE

parameters.jsCode:
const stdout = $input.first()?.json?.stdout || '';
let payload;
try {
  payload = JSON.parse(stdout);
} catch (error) {
  payload = {
    success: false,
    error_code: 'invalid_probe_json',
    message: error.message || String(error),
    raw_stdout: stdout.slice(0, 4000),
  };
}
return [{ json: payload }];

const data = $input.first().json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.sentMap) staticData.sentMap = {};
const sentMap = staticData.sentMap;
const nowMs = Date.now();
const severityCooldownMs = {
  critical: 30 * 60 * 1000,
  high: 2 * 60 * 60 * 1000,
  medium: 6 * 60 * 60 * 1000,
};
const alertPolicy = {
  managerFollowupGraceMs: 10 * 60 * 1000,
  unassignedActiveGraceMs: 20 * 60 * 1000,
  reviewGraceMs: 30 * 60 * 1000,
  heartbeatByOwner: {
    CEO: { enabled: true, multiplier: 1.25, severity: 'high' },
    CTO: { enabled: true, multiplier: 1.25, severity: 'high' },
    Trader: { enabled: true, multiplier: 2.0, severity: 'medium' },
    Scout: { enabled: true, multiplier: 2.0, severity: 'medium' },
    'KR Scout': { enabled: false },
    'Staff Engineer': { enabled: false },
    'Software Engineer': { enabled: false },
    'QA Engineer': { enabled: false },
    'Release Engineer': { enabled: false },
    'Code Reviewer': { enabled: false },
  },
};
const NL = String.fromCharCode(10);

function parseIso(value) {
  if (!value || typeof value !== 'string') return null;
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
}

function isActiveIssue(status, includeBacklog = false) {
  const normalized = String(status || '').trim().toLowerCase();
  if (normalized === 'in_progress' || normalized === 'blocked') return true;
  return includeBacklog && (normalized === 'backlog' || normalized === 'todo');
}

function fingerprint(kind, ...parts) {
  return [kind, ...parts.filter(Boolean)].join(':');
}

function groupChildren(issues) {
  const grouped = {};
  for (const issue of issues) {
    if (!issue || typeof issue !== 'object') continue;
    if (!issue.parentId) continue;
    if (!grouped[issue.parentId]) grouped[issue.parentId] = [];
    grouped[issue.parentId].push(issue);
  }
  return grouped;
}

function activeIssuesByAssignee(issues) {
  const grouped = {};
  for (const issue of issues) {
    if (!issue || typeof issue !== 'object') continue;
    if (!issue.assigneeAgentId) continue;
    if (!isActiveIssue(issue.status, false)) continue;
    if (!grouped[issue.assigneeAgentId]) grouped[issue.assigneeAgentId] = [];
    grouped[issue.assigneeAgentId].push(issue);
  }
  return grouped;
}

function heartbeatRowsByAgent(rows) {
  const grouped = {};
  for (const row of rows || []) {
    if (!row || typeof row !== 'object') continue;
    if (!row.agentId) continue;
    if (!grouped[row.agentId]) grouped[row.agentId] = [];
    grouped[row.agentId].push(row);
  }
  return grouped;
}

function latestTimerHeartbeat(rows) {
  let latest = null;
  for (const row of rows || []) {
    if (String(row.invocationSource || '') !== 'timer') continue;
    const startedAt = parseIso(row.startedAt);
    if (!startedAt) continue;
    if (!latest || startedAt > latest) latest = startedAt;
  }
  return latest;
}

function stripTrailingSlash(value) {
  return String(value || '').replace(/\/+$/, '');
}

function resolveItemCompanyPrefix(item, source) {
  const explicit = String(source?.company_prefix || '').trim();
  if (explicit) return explicit.toUpperCase();
  const identifier = String(item?.issue_identifier || '').trim();
  const match = /^([A-Za-z][A-Za-z0-9_]*)-\d+$/.exec(identifier);
  return match ? match[1].toUpperCase() : 'ROB';
}

function buildIssueDeepLink(item, source) {
  const issueRef = String(item?.issue_identifier || '').trim();
  if (!issueRef) return null;
  const appBase = stripTrailingSlash(source?.app_base || source?.api_base || 'http://raspberrypi:3100');
  const companyPrefix = encodeURIComponent(resolveItemCompanyPrefix(item, source));
  return `${appBase}/${companyPrefix}/issues/${encodeURIComponent(issueRef)}`;
}

function buildApprovalDeepLink(item, source) {
  const approvalId = String(item?.approval_id || item?.evidence?.approval_id || '').trim();
  if (!approvalId) return null;
  const appBase = stripTrailingSlash(source?.app_base || source?.api_base || 'http://raspberrypi:3100');
  const companyPrefix = encodeURIComponent(resolveItemCompanyPrefix(item, source));
  return `${appBase}/${companyPrefix}/approvals/${encodeURIComponent(approvalId)}`;
}

function deriveItems(snapshot, warnings) {
  const issues = Array.isArray(snapshot?.issues) ? snapshot.issues : [];
  const approvals = Array.isArray(snapshot?.approvals) ? snapshot.approvals : [];
  const agents = Array.isArray(snapshot?.agents) ? snapshot.agents : [];
  const activeIssuesByAgent = activeIssuesByAssignee(issues);
const heartbeatRows = heartbeatRowsByAgent(Array.isArray(snapshot?.heartbeat_runs) ? snapshot.heartbeat_runs : []);
  const agentById = Object.fromEntries(agents.filter(a => a && a.id).map(a => [a.id, a]));
  const childByParent = groupChildren(issues);
  const items = [];

  for (const issue of issues) {
    if (!issue || typeof issue !== 'object') continue;
    const issueId = issue.id;
    const identifier = issue.identifier || issue.id || 'unknown';
    const title = issue.title || 'Untitled';
    const status = issue.status || '';
    const assigneeAgentId = issue.assigneeAgentId || null;

    if (issueId && isActiveIssue(status, false) && assigneeAgentId && agentById[assigneeAgentId] && childByParent[issueId]?.length) {
      const agent = agentById[assigneeAgentId];
      const latestChildUpdate = childByParent[issueId]
        .map(child => parseIso(child.updatedAt))
        .filter(Boolean)
        .sort((a, b) => b - a)[0] || null;
      const lastHeartbeat = parseIso(agent.lastHeartbeatAt);
      const followupAgeMs = latestChildUpdate ? nowMs - latestChildUpdate.getTime() : 0;
      if (latestChildUpdate && followupAgeMs >= alertPolicy.managerFollowupGraceMs && (!lastHeartbeat || latestChildUpdate > lastHeartbeat)) {
        const owner = agent.name || assigneeAgentId;
        items.push({
          fingerprint: fingerprint('manager_followup_needed', identifier, latestChildUpdate.toISOString()),
          kind: 'manager_followup_needed',
          severity: 'critical',
          owner,
          issue_identifier: identifier,
          title,
          summary: '자식 이슈 업데이트가 assignee 마지막 heartbeat보다 최신',
          evidence: {
            latest_child_update: latestChildUpdate.toISOString(),
            last_heartbeat_at: lastHeartbeat ? lastHeartbeat.toISOString() : null,
            followup_age_minutes: Math.round(followupAgeMs / 60000),
          },
          recommended_action: `${owner} 재실행 또는 parent issue 확인`,
        });
      }
    }

    const updatedAt = parseIso(issue.updatedAt);
    const unassignedAgeMs = updatedAt ? nowMs - updatedAt.getTime() : alertPolicy.unassignedActiveGraceMs;
    if (isActiveIssue(status, false) && !assigneeAgentId && unassignedAgeMs >= alertPolicy.unassignedActiveGraceMs) {
      items.push({
        fingerprint: fingerprint('active_issue_unassigned', identifier, issue.updatedAt || ''),
        kind: 'active_issue_unassigned',
        severity: 'high',
        owner: null,
        issue_identifier: identifier,
        title,
        summary: '활성 이슈에 assignee가 없다',
        evidence: {
          status,
          updated_at: issue.updatedAt || null,
          unassigned_age_minutes: Math.round(unassignedAgeMs / 60000),
        },
        recommended_action: 'owner 지정 또는 backlog 복귀 여부 확인',
      });
    }
  }

  for (const approval of approvals) {
    if (!approval || typeof approval !== 'object') continue;
    if (String(approval.status || '') !== 'revision_requested') continue;
    const payload = approval.payload && typeof approval.payload === 'object' ? approval.payload : {};
    const title = payload.title || payload.name || approval.type || 'Approval';
    items.push({
      fingerprint: fingerprint('approval_revision_requested', approval.id || 'unknown', approval.updatedAt || ''),
      kind: 'approval_revision_requested',
      severity: 'high',
      owner: 'board',
      issue_identifier: null,
      approval_id: approval.id || null,
      title,
      summary: 'approval이 revision_requested 상태다',
      evidence: {
        approval_id: approval.id || null,
        type: approval.type || null,
        updated_at: approval.updatedAt || null,
      },
      recommended_action: 'approval 재검토 또는 수정 요청 확인',
    });
  }

  // issue_review_needed / formal_approval_pending
  const pendingApprovalsByIssue = {};
  for (const approval of approvals) {
    if (!approval || typeof approval !== 'object') continue;
    if (String(approval.status || '') !== 'pending') continue;
    for (const issueId of (approval.issueIds || [])) {
      if (!issueId) continue;
      if (!pendingApprovalsByIssue[issueId]) pendingApprovalsByIssue[issueId] = [];
      pendingApprovalsByIssue[issueId].push(approval);
    }
  }

  for (const issue of issues) {
    if (!issue || typeof issue !== 'object') continue;
    if (String(issue.status || '').trim().toLowerCase() !== 'in_review') continue;
    const issueId = issue.id;
    const identifier = issue.identifier || issue.id || 'unknown';
    const title = issue.title || 'Untitled';
    const updatedAt = parseIso(issue.updatedAt);
    const reviewAgeMs = updatedAt ? nowMs - updatedAt.getTime() : 0;
    if (updatedAt && reviewAgeMs < alertPolicy.reviewGraceMs) continue;

    const assigneeUserId = issue.assigneeUserId || null;
    const assigneeAgentId = issue.assigneeAgentId || null;

    if (assigneeUserId) {
      const linkedApprovals = pendingApprovalsByIssue[issueId] || [];
      if (linkedApprovals.length > 0) {
        for (const appr of linkedApprovals) {
          const approvalId = appr.id || '';
          items.push({
            fingerprint: fingerprint('formal_approval_pending', identifier, approvalId),
            kind: 'formal_approval_pending',
            severity: 'high',
            owner: 'board',
            issue_identifier: identifier,
            approval_id: approvalId,
            title,
            summary: 'in_review 이슈에 pending approval이 있다',
            evidence: {
              approval_id: approvalId,
              assignee_user_id: assigneeUserId,
              updated_at: issue.updatedAt || null,
            },
            recommended_action: 'approval 검토 및 승인/반려 결정',
          });
        }
      } else {
        items.push({
          fingerprint: fingerprint('issue_review_needed', identifier, assigneeUserId),
          kind: 'issue_review_needed',
          severity: 'high',
          owner: 'board',
          issue_identifier: identifier,
          role_tag: 'Boss',
          title,
          summary: 'in_review 이슈가 사람 검토 대기 중이다',
          evidence: {
            assignee_user_id: assigneeUserId,
            updated_at: issue.updatedAt || null,
          },
          recommended_action: '이슈 검토 후 승인 또는 피드백 전달',
        });
      }
    } else if (assigneeAgentId) {
      const agentName = agentById[assigneeAgentId]
        ? (agentById[assigneeAgentId].name || assigneeAgentId)
        : assigneeAgentId;
      items.push({
        fingerprint: fingerprint('misrouted_review', identifier, assigneeAgentId),
        kind: 'misrouted_review',
        severity: 'medium',
        owner: agentName,
        issue_identifier: identifier,
        role_tag: agentName,
        title,
        summary: 'in_review인데 agent만 할당되어 있다 (사람 reviewer 없음)',
        evidence: {
          assignee_agent_id: assigneeAgentId,
          agent_name: agentName,
          updated_at: issue.updatedAt || null,
        },
        recommended_action: '사람 reviewer 할당 또는 상태 재조정',
      });
    }
    // in_review + no assignee at all → falls through to active_issue_unassigned
  }

  for (const agent of agents) {
    if (!agent || typeof agent !== 'object') continue;
    const heartbeat = agent.runtimeConfig?.heartbeat;
    if (!heartbeat || heartbeat.enabled !== true) continue;
    const intervalSec = Number(heartbeat.intervalSec || 0);
    if (!intervalSec || intervalSec <= 0) continue;
    const agentId = agent.id;
    if (!agentId) continue;
    const owner = agent.name || agentId;
    const heartbeatPolicy = alertPolicy.heartbeatByOwner[owner] || { enabled: false };
    if (!heartbeatPolicy.enabled) continue;

    let latestReference = latestTimerHeartbeat(heartbeatRows[agentId] || []);
    let usedFallback = false;
    if (!latestReference) {
      latestReference = parseIso(agent.lastHeartbeatAt);
      usedFallback = Boolean(latestReference);
    }
    if (!latestReference) continue;

    const activeIssues = activeIssuesByAgent[agentId] || [];
    if (!activeIssues.length) continue;
    const contextIssue = activeIssues.reduce((latest, issue) => {
      const latestAt = parseIso(latest?.updatedAt) || parseIso(latest?.createdAt) || new Date(0);
      const issueAt = parseIso(issue?.updatedAt) || parseIso(issue?.createdAt) || new Date(0);
      return issueAt > latestAt ? issue : latest;
    }, activeIssues[0]);

    const ageMs = nowMs - latestReference.getTime();
    const thresholdMultiplier = Number(heartbeatPolicy.multiplier || 1.5);
    if (ageMs <= intervalSec * 1000 * thresholdMultiplier) continue;
    if (usedFallback) {
      warnings.push(`heartbeat_missed used agent.lastHeartbeatAt fallback for agent ${agentId}`);
    }
    items.push({
      fingerprint: fingerprint('heartbeat_missed', owner, latestReference.toISOString()),
      kind: 'heartbeat_missed',
      severity: heartbeatPolicy.severity || 'medium',
      owner,
      issue_identifier: String(contextIssue?.identifier || '').trim() || null,
      title: String(contextIssue?.title || `${owner} heartbeat missed`),
      summary: 'expected timer heartbeat보다 마지막 실행이 오래됐다',
      evidence: {
        last_heartbeat_at: latestReference.toISOString(),
        age_seconds: Math.round(ageMs / 1000),
        interval_sec: intervalSec,
        threshold_multiplier: thresholdMultiplier,
      },
      recommended_action: `${owner} 상태 확인 또는 수동 heartbeat 검토`,
    });
  }

  return items;
}

function severityEmoji(severity) {
  return severity === 'critical' ? '🚨' : severity === 'high' ? '⚠️' : 'ℹ️';
}

function buildMessage(notifyItems, resolvedCount, warnings, source) {
  const top = notifyItems.slice(0, 5);
  const lines = [];
  lines.push(`🚨 Boss Action Queue (${notifyItems.length}건)`);
  lines.push('');
  top.forEach((item, idx) => {
    if (item.kind === 'issue_review_needed') {
      const tag = item.role_tag || 'Boss';
      lines.push(`${idx + 1}. 🔍 [${tag}] ${item.issue_identifier || item.title} — 검토 필요`);
    } else if (item.kind === 'formal_approval_pending') {
      lines.push(`${idx + 1}. 📋 [Boss] ${item.issue_identifier || item.title} — approval 필요`);
    } else if (item.kind === 'misrouted_review') {
      const tag = item.role_tag || item.owner || 'unknown';
      lines.push(`${idx + 1}. ⚠️ [${tag}] ${item.issue_identifier || item.title} — 잘못된 상태 (in_review인데 agent만 할당)`);
    } else {
      lines.push(`${idx + 1}. ${severityEmoji(item.severity)} [${item.severity}] ${item.issue_identifier || item.title}`);
    }
    lines.push(`- ${item.summary}`);
    if (item.recommended_action) lines.push(`- 제안: ${item.recommended_action}`);
    if (item.evidence?.last_heartbeat_at) lines.push(`- last heartbeat: ${item.evidence.last_heartbeat_at}`);
    if (item.evidence?.latest_child_update) lines.push(`- latest child update: ${item.evidence.latest_child_update}`);
    const issueDeepLink = buildIssueDeepLink(item, source);
    const approvalDeepLink = buildApprovalDeepLink(item, source);
    if (issueDeepLink) lines.push(`- issue: ${issueDeepLink}`);
    if (approvalDeepLink) lines.push(`- approval: ${approvalDeepLink}`);
  });
  if (notifyItems.length > top.length) {
    lines.push('');
    lines.push(`외 ${notifyItems.length - top.length}건`);
  }
  if (resolvedCount > 0) {
    lines.push('');
    lines.push(`✅ resolved ${resolvedCount}건`);
  }
  if (warnings.length > 0) {
    lines.push('');
    lines.push('Warnings:');
    warnings.slice(0, 3).forEach(w => lines.push(`- ${w}`));
  }
  return lines.join(NL);
}

if (!data.success) {
  const key = `probe_error:${data.error_code || 'unknown'}`;
  const cooldown = severityCooldownMs.high;
  const previous = sentMap[key];
  const shouldNotify = !previous || (nowMs - (previous.lastNotifiedAt || 0)) > cooldown;
  if (shouldNotify) {
    sentMap[key] = { lastNotifiedAt: nowMs, severity: 'high' };
  }
  const message = [
    '⚠️ Paperclip Boss Action Queue probe issue',
    `- code: ${data.error_code || 'unknown'}`,
    `- message: ${data.message || 'unknown error'}`,
    ...(Array.isArray(data.remediation) ? data.remediation.map(line => `- ${line}`) : []),
  ].join(NL);
  return [{ json: { shouldNotify, message, notifyCount: shouldNotify ? 1 : 0, errorCode: data.error_code || 'unknown' } }];
}

const warnings = Array.isArray(data.warnings) ? [...data.warnings] : [];
const items = deriveItems(data.snapshot || {}, warnings);
const currentKeys = new Set(items.map(item => item.fingerprint));
const resolvedKeys = [];
for (const key of Object.keys(sentMap)) {
  if (key.startsWith('probe_error:')) continue;
  if (!currentKeys.has(key)) {
    resolvedKeys.push(key);
    delete sentMap[key];
  }
}

const notifyItems = [];
for (const item of items) {
  const cooldown = severityCooldownMs[item.severity] || severityCooldownMs.medium;
  const previous = sentMap[item.fingerprint];
  const shouldNotify = !previous || previous.severity !== item.severity || (nowMs - (previous.lastNotifiedAt || 0)) > cooldown;
  if (shouldNotify) {
    notifyItems.push(item);
    sentMap[item.fingerprint] = { lastNotifiedAt: nowMs, severity: item.severity };
  }
}

const shouldNotify = notifyItems.length > 0 || resolvedKeys.length > 0;
const message = shouldNotify ? buildMessage(notifyItems, resolvedKeys.length, warnings, data.source || {}) : '';
return [{ json: { shouldNotify, message, notifyCount: notifyItems.length, resolvedCount: resolvedKeys.length } }];
